namespace Components;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@namespace Components

<div class="checkout-wizard">
    @if (_step == 1)
    {
        <ShippingStep Shipping="@_order.Shipping" OnNext="@GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="@_order.Payment" OnBack="@GoToShipping" OnPlaceOrder="@PlaceOrder" />
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private int _step = 1;

    private void GoToPayment()
    {
        _step = 2;
    }

    private void GoToShipping()
    {
        _step = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace Components

<h3>Shipping Information</h3>

<div class="form-group">
    <label>Name</label>
    <input @bind="Shipping.Name" @bind:event="oninput" />
</div>

<div class="form-group">
    <label>Address</label>
    <input @bind="Shipping.Address" @bind:event="oninput" />
</div>

<div class="form-group">
    <label>City</label>
    <input @bind="Shipping.City" @bind:event="oninput" />
</div>

<div class="form-group">
    <label>Zip Code</label>
    <input @bind="Shipping.ZipCode" @bind:event="oninput" />
</div>

@if (!string.IsNullOrWhiteSpace(_validationMessage))
{
    <p class="validation-error">@_validationMessage</p>
}

<button @onclick="Next">Next</button>

@code {
    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private string _validationMessage = "";

    private async Task Next()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            _validationMessage = "Name and Address are required.";
            return;
        }

        _validationMessage = "";
        await OnNext.InvokeAsync();
    }
}

@namespace Components

<h3>Payment Information</h3>

<div class="form-group">
    <label>Card Number</label>
    <input @bind="Payment.CardNumber" @bind:event="oninput" />
</div>

<div class="form-group">
    <label>Expiry Date</label>
    <input @bind="Payment.ExpiryDate" @bind:event="oninput" />
</div>

<button @onclick="Back">Back</button>
<button @onclick="PlaceOrder">Place Order</button>

@code {
    [Parameter]
    public PaymentInfo Payment { get; set; } = new();

    [Parameter]
    public EventCallback OnBack { get; set; }

